// Берём текст из output предыдущей ноды
const longText = $input.item.json.output || "";

// Telegram ограничение (4096 символов, но оставляем запас)
const MAX_LENGTH = 4000;

// --- Функция безопасного экранирования под MarkdownV2 ---
function escapeMarkdownV2(text) {
    return text
        .replace(/([_*\[\]()~`>#+=|{}.!\\-])/g, '\\$1'); // экранируем спецсимволы
}

// --- Функция разбивки на части по максимуму 4000 символов ---
function splitTelegramMessage(text, maxLength = MAX_LENGTH) {
    if (!text) return [];

    const chunks = [];
    let start = 0;

    while (start < text.length) {
        let end = start + maxLength;

        if (end >= text.length) {
            chunks.push(text.slice(start));
            break;
        }

        // Разбиваем по последнему переводу строки (если есть)
        let lastNewLine = text.lastIndexOf("\n", end);
        if (lastNewLine <= start) lastNewLine = end;

        chunks.push(text.slice(start, lastNewLine));
        start = lastNewLine;
    }

    return chunks;
}

// --- Применяем экранирование и разбивку ---
const safeText = escapeMarkdownV2(longText);
const messages = splitTelegramMessage(safeText);

// --- Возвращаем массив сообщений для Telegram-ноды ---
return messages.map(msg => ({
    json: {
        message: msg,
        parse_mode: "MarkdownV2" // обязательно указать для Telegram
    }
}));

